import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const o=JSON.parse('{"title":"血肉（Caro）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/realms/caro.md","filePath":"ja/realms/caro.md","lastUpdated":1775394001000}'),n={name:"ja/realms/caro.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="血肉-caro" tabindex="-1">血肉（Caro） <a class="header-anchor" href="#血肉-caro" aria-label="Permalink to &quot;血肉（Caro）&quot;">​</a></h1><p><span class="realm-badge realm-caro">血肉</span></p><p><strong>血肉</strong>はクトゥルフ神話における肉体変容やシュブ＝ニグラスの豊穣をテーマとした界域です。胚胎システムと吞噬メカニクスを駆使するハイリスク・ハイリターンの戦闘スタイルが特徴です。神父（萨尔瓦多）+専属運命の輪の実装後、深海と並ぶS級界域になりました。</p><h2 id="テーマ・世界観" tabindex="-1">テーマ・世界観 <a class="header-anchor" href="#テーマ・世界観" aria-label="Permalink to &quot;テーマ・世界観&quot;">​</a></h2><p>血肉界域はシュブ＝ニグラスの眷属や、肉体の変容・進化に関わる存在の力を宿す領域です。覚醒体たちは自身の肉体を犠牲にしながら、その痛みを攻撃力へと変換します。</p><h2 id="戦闘スタイル" tabindex="-1">戦闘スタイル <a class="header-anchor" href="#戦闘スタイル" aria-label="Permalink to &quot;戦闘スタイル&quot;">​</a></h2><ul><li><strong>胚胎システム</strong> — 血肉界域才能発動後、チーム上部に胚胎ゲージが表示。血肉覚醒体のスキルで胚融合を蓄積し、100%到達で手札に「胚」カードを1枚追加</li><li><strong>吞噬メカニクス</strong> — 手札に「胚」カードがある時、血肉覚醒体の狂気爆発と組み合わせて「吞噬」効果を発動。胚を消費して超強力な効果を発動</li><li><strong>胚胎回転加速</strong> — 胚胎は全チームの狂気回復を加速し、大招（超限）の出力を強化</li><li><strong>純血肉共鳴</strong> — 純血肉編成時に特殊な強化効果を発動</li></ul><h2 id="血肉界域の覚醒体" tabindex="-1">血肉界域の覚醒体 <a class="header-anchor" href="#血肉界域の覚醒体" aria-label="Permalink to &quot;血肉界域の覚醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体名</th><th style="text-align:center;">レア</th><th style="text-align:center;">役割</th><th style="text-align:center;">Tier</th><th style="text-align:left;">入手</th></tr></thead><tbody><tr><td style="text-align:left;">尤乌哈希 (Uvhash)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">雷娅 (Rhea)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T0</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">索蕾尔 (Sorel)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">爱丽丝 (Alice)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">菲茵特 (Faint)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">阿格里帕 (Agrippa)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">希洛 (Shilo)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T3</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">泰旖丝 (Thais)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">萨尔瓦多 (Salvador)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">艾继丝 (Aigis)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">血链·希洛 (Helot)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">杜勒赛因 (Doresain)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">莱 (Leigh)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">合唱型</td><td style="text-align:center;">—</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">徐 (Xu)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">合唱型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr></tbody></table><h2 id="おすすめ編成" tabindex="-1">おすすめ編成 <a class="header-anchor" href="#おすすめ編成" aria-label="Permalink to &quot;おすすめ編成&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>血肉界域は上手難度が最も高い界域です。胚胎ゲージと血量のコントロールが鍵となります。界域精通34以上で毎ターン+35の胚融合値を自然蓄積できます。戦闘終了時には補助のエネルギー満タン+胚融合70-100%を維持するのが理想です。</p></div><h3 id="尤乌哈希標準血肉チーム" tabindex="-1">尤乌哈希標準血肉チーム <a class="header-anchor" href="#尤乌哈希標準血肉チーム" aria-label="Permalink to &quot;尤乌哈希標準血肉チーム&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">尤乌哈希 (Uvhash)</td><td style="text-align:left;">主火力</td></tr><tr><td style="text-align:center;">コア補助</td><td style="text-align:left;">雷娅 (Rhea)</td><td style="text-align:left;">胚胎吞噬で大量回復。血肉チーム不可欠の「2」</td></tr><tr><td style="text-align:center;">胚胎管理</td><td style="text-align:left;">艾继丝 (Aigis)</td><td style="text-align:left;">胚胎生産/管理。血肉チーム不可欠の「2」</td></tr><tr><td style="text-align:center;">防御</td><td style="text-align:left;">菲茵特 (Faint)</td><td style="text-align:left;">防御。死亡抵抗発動後に全チーム回復強化</td></tr></tbody></table><p>覚醒優先順位：艾继丝 &gt; 雷娅 &gt; 尤乌哈希 &gt; 菲茵特</p><h3 id="神父チーム-top3最強編成" tabindex="-1">神父チーム（Top3最強編成） <a class="header-anchor" href="#神父チーム-top3最強編成" aria-label="Permalink to &quot;神父チーム（Top3最強編成）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">萨尔瓦多 (Salvador)</td><td style="text-align:left;">主火力。「神父」</td></tr><tr><td style="text-align:center;">コア補助</td><td style="text-align:left;">雷娅 (Rhea)</td><td style="text-align:left;">神父の2費カードを複製してHPサイクル形成</td></tr><tr><td style="text-align:center;">胚胎補助</td><td style="text-align:left;">艾继丝 (Aigis)</td><td style="text-align:left;">胚胎管理</td></tr><tr><td style="text-align:center;">フレキシブル</td><td style="text-align:left;">24 / 拉蒙娜</td><td style="text-align:left;">弾性DPS</td></tr></tbody></table><p>密契推奨：诅咒兔（会心率/会心ダメージ）。補助枠は界域精通を優先。</p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">界域概要</a></li><li><a href="./chaos.html">混沌（Chaos）</a></li><li><a href="./aequor.html">深海（Aequor）</a></li><li><a href="./ultra.html">超維（Ultra）</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',19)])])}const h=e(n,[["render",r]]);export{o as __pageData,h as default};
